function sleep(ms) {
  execSync(`sleep ${ms / 1000}`);
}

function fetchWebsiteContent(url, timeout = 10) {
  try {
    const result = execSync(
      `curl -L -s --max-time ${timeout} -A "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36" "${url}"`,
      { encoding: 'utf8', maxBuffer: 10 * 1024 * 1024 }
    );
    return result;
  } catch (e) {
    console.error(`Error fetching ${url}:`, e.message);
    return '';
  }
}

function findContactEmails(htmlContent, website) {
  const emailPattern = /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g;
  const emails = htmlContent.match(emailPattern) || [];

  // Filter out common noise emails
  const noise = ['example.com', 'sentry.io', 'schema.org', 'w3.org', 'placeholder', 'example@', 'wixpress.com', 'shopify.com', 'myshopify.com'];
  const filtered = emails.filter(e => !noise.some(n => e.toLowerCase().includes(n)));

  // Prioritize marketing/press/contact related emails
  const priorityKeywords = ['marketing', 'press', 'media', 'contact', 'info', 'partnerships', 'brand', 'hello', 'support'];
  const priorityEmails = filtered.filter(e => priorityKeywords.some(k => e.toLowerCase().includes(k)));

  if (priorityEmails.length > 0) {
    return [...new Set(priorityEmails)].slice(0, 3);
  } else if (filtered.length > 0) {
    return [...new Set(filtered)].slice(0, 3);
  }
  return [];
}

function analyzeUgcPresence(htmlContent) {
  const htmlLower = htmlContent.toLowerCase();

  const ugcIndicators = {
    instagram_feed: htmlLower.includes('instagram') && (htmlLower.includes('feed') || htmlLower.includes('gallery')),
    hashtag_campaign: htmlContent.includes('#') && (htmlLower.includes('instagram') || htmlLower.includes('share')),
    customer_photos: htmlLower.includes('customer photo') || htmlLower.includes('customer image'),
    ugc_gallery: htmlLower.includes('user generated') || htmlLower.includes('community gallery'),
    social_proof: htmlLower.includes('shop the look') || htmlLower.includes('worn by') || htmlLower.includes('tagged in'),
  };

  const activeFeatures = Object.entries(ugcIndicators).filter(([k, v]) => v).map(([k]) => k);

  if (activeFeatures.length === 0) {
    return "None visible";
  } else if (activeFeatures.length === 1) {
    return `Limited (${activeFeatures[0].replace(/_/g, ' ')})`;
  } else {
    return `Some UGC present (${activeFeatures.length} features)`;
  }
}

function generateUgcBenefit(brandName, segment, currentStrategy) {
  const benefits = {
    "Fast Fashion": "High volume of customer purchases creates strong UGC potential; customers want to see real-world styling; builds trust and drives conversions",
    "Athleisure/Sportswear": "Community-driven category; customers want to see products in action; perfect for before/after, workout content, and lifestyle shots",
    "Contemporary/Premium": "Customers seek style inspiration and validation; UGC provides social proof for higher price points; builds aspirational community",
    "Denim/Casual": "Fit and styling are key purchase factors; real customer photos show how products look on different body types; reduces returns",
    "Streetwear/Urban": "Highly visual, style-driven category; customers want to see how others style pieces; strong social media culture",
    "Department Store Brands": "Wide product range benefits from diverse customer content; UGC helps customers discover styling options across categories",
    "Affordable Luxury": "Social proof helps justify price point; customers want to see quality and styling in real contexts; builds brand community",
    "Activewear Retail": "Performance and lifestyle content resonates; customers want to see products in use; strong community aspect",
    "Specialty Retail": "Unique aesthetic benefits from customer interpretation; UGC reinforces brand identity and lifestyle positioning",
  };

  const baseBenefit = benefits[segment] || "Physical stores create opportunity for in-store UGC missions; customer content drives online engagement";

  if (currentStrategy.toLowerCase().includes('none')) {
    return `${baseBenefit}. Currently missing UGC integration - major opportunity.`;
  } else if (currentStrategy.toLowerCase().includes('limited')) {
    return `${baseBenefit}. Has minimal UGC - could expand significantly with dedicated widget.`;
  } else {
    return `${baseBenefit}. Already using some UGC - shows understanding of value, could optimize with missions widget.`;
  }
}

function researchBrand(brandName, website, segment) {
  console.log(`Researching ${brandName}...`);

  const result = {
    brand_name: brandName,
    website: website,
    segment: segment,
    emails: [],
    ugc_strategy: 'Unknown',
    store_info: 'Physical stores present',
    why_ugc: '',
  };

  // Try homepage
  let html = fetchWebsiteContent(website);
  sleep(1000);

  if (html) {
    result.ugc_strategy = analyzeUgcPresence(html);
    result.emails.push(...findContactEmails(html, website));
  }

  // Try contact pages
  const contactUrls = [
    `${website}/contact`,
    `${website}/contact-us`,
    `${website}/press`,
    `${website}/media`,
    `${website}/about`,
  ];

  for (const contactUrl of contactUrls.slice(0, 2)) {
    if (result.emails.length > 0) break;

    html = fetchWebsiteContent(contactUrl);
    if (html) {
      result.emails.push(...findContactEmails(html, website));
    }
    sleep(1000);
  }

  // Generate UGC benefit analysis
  result.why_ugc = generateUgcBenefit(brandName, segment, result.ugc_strategy);

  // Deduplicate emails
  result.emails = [...new Set(result.emails)].slice(0, 2);

  return result;
}

function main() {
  console.log('Starting fashion brand research...\n');
  const allResults = [];

  for (const [segment, brands] of Object.entries(BRANDS_TO_RESEARCH)) {
    console.log('='.repeat(60));
    console.log(`Researching ${segment} brands`);
    console.log('='.repeat(60));

    for (const brandInfo of brands) {
      try {
        const result = researchBrand(brandInfo.name, brandInfo.website, segment);
        result.regions = brandInfo.region;
        allResults.push(result);
        console.log(`✓ ${brandInfo.name}: ${result.emails.length} emails found, Strategy: ${result.ugc_strategy}`);
      } catch (e) {
        console.error(`✗ Error researching ${brandInfo.name}:`, e.message);
      }

      sleep(2000); // Be respectful
    }
  }

  // Save results to CSV
  console.log('\n' + '='.repeat(60));
  console.log('Saving results to CSV...');
  console.log('='.repeat(60));

  const csvRows = [
    ['Brand Name', 'Website', 'Email Contact', 'Contact Title/Type', 'Industry Segment', 'Approximate Store Count/Regions', "Why They'd Benefit from UGC", 'Current UGC Strategy']
  ];

  for (const result of allResults) {
    const email = result.emails[0] || 'Contact form only';
    const contactType = result.emails.length > 0 ? 'Marketing/Press' : 'General Contact';

    csvRows.push([
      result.brand_name,
      result.website,
      email,
      contactType,
      result.segment,
      `${result.regions} - Multiple stores`,
      result.why_ugc,
      result.ugc_strategy
    ]);
  }

  // Write CSV
  const csvContent = csvRows.map(row => 
    row.map(cell => {
      // Escape quotes and wrap in quotes if contains comma, quote, or newline
      const escaped = String(cell).replace(/"/g, '""');
      return /[",\n]/.test(cell) ? `"${escaped}"` : escaped;
    }).join(',')
  ).join('\n');

  fs.writeFileSync('/job/data/fashion-brands-ugc-leads.csv', csvContent);

  console.log(`\n✓ Successfully researched ${allResults.length} brands`);
  console.log('✓ CSV saved to /job/data/fashion-brands-ugc-leads.csv');

  // Save detailed results as JSON for summary report
  fs.writeFileSync('/job/tmp/research_results.json', JSON.stringify(allResults, null, 2));

  return allResults;
}

